INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0605180N$$, 2026, $$The E-6 Take Charge and Move Out (TACAMO) Recapitalization Program (E-130J) provides for air vehicle replacement and mission systems modernization to augment
and eventually replace the aging E-6B aircraft for the TACAMO mission. The TACAMO mission provides an airborne capability for survivable, endurable and reliable
airborne command, control and communications between the United States (U.S.) National Command Authority (NCA) and the U.S. strategic forces. This mission
is critical in the deterrence and management of a nuclear conflict. A dedicated communications platform, TACAMO aircraft features the ability to communicate on
virtually every radio frequency band from very low frequency (VLF) up through advanced extremely high frequency (AEHF) using a variety of modulations, encryptions
and networks, minimizing the likelihood an emergency message being jammed by an enemy. The EMD Hardware Development efforts for the design, architecture,
and integration of a cyber-resilient communications systems to transform a modified C-130J-30 into E-130J through an Engineering & Manufacturing Development
(EMD) Contract awarded in FY 2025. Included in these efforts are Government and Contractor Systems Integration Laboratories, Contractor System Test Integration
Laboratory, Government Furnished Property (National Security Agency approved encryption devices, Ultra High Frequency modems), High Frequency and the
Advanced Extremely High Frequency solutions, Top Secret network development and building required infrastructure includes power generation systems, cooling, flight
deck avionics, Electric Magnetic Pulse (EMP) hardening, cyber hardening, and structural modifications to support integration of E-130J mission system equipment. FY
2026 funding includes purchase for startup materials needed for three (3) C-130J-30 Government Furnished Equipment (GFE) System Demonstration Test Articles
(SDTA) for mission system integration.

