$$, $$4bf2e56341e8de345371fc9bd9d15b1a9b7fc060976ddf8d2967382e013404a1$$, $${"A": "5dc288ef19054f8966ec27ca882e84c8a7bd04d2771be6deb80949f362108596", "C": "d4fdf923ba776b98bda680220afe7660b2fb7f78e25f4cb026ad0b29031d9620", "D": "dd3cc97fbc1f83044e7108d890282c985bc0c0369f6126d8f9279f6daeb4325b"}$$::jsonb, $$Budget J-Books/FY26/Navy/RDTEN_BA6_Book.pdf$$, 107, $$2026-05-10T04:04:10.303429+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$1203330SF$$, 2026, $$The Space Superiority Intelligence (SSI) program provides intelligence for key find, fix, track, target, engage, and assess requirements supporting Space Superiority
activities meeting Combatant Command (CCMD) needs for Space Operations Command (SpOC). SSI funds developmental intelligence activities to support new
space superiority capability acquisition and development. Funds associated developmental intelligence Planning and direction, Collection, Processing and exploitation,
Analysis and production, Dissemination and integration (PCPAD) capabilities providing Battlespace Awareness and Space Domain Awareness (SDA) in support of
Space Superiority and Space Control. This includes funding for fixed and transportable intelligence collection; Processing, Exploitation and Dissemination (PED);
analysis and production capabilities that are modular (plug-and-play); meet Risk Management Framework Accreditation requirements and can keep pace with
technological advances and emerging threats. It provides intelligence support systems for SDA activities that provide the requisite current and predictive knowledge
of space events and threat conditions and intelligence support to the Space Security and Defense Program (SSDP) by providing architectural survivability analysis of
critical mission assets for mission assurance, as well as network analysis. It also supports specialized/tailored, phased threat system analysis and studies (A&S), test
support, lab equipment, and Material Acquisition and Exploitation (MAE) for system development, vulnerability, susceptibility assessments to support tactics, techniques
and procedures (TTP) development, and future threat technology studies necessary for mission area success, achievement of space superiority, and to preserve the
US space advantage across all domains.

 Space acquisition must respond with speed and agility to the proliferation of emerging space adversary threats and new technologies. In support of these nascent,
 cutting edge space acquisition capabilities, Space Superiority Intelligence provides exquisite, crucial cryptologic and other intelligence through transformational collection
 and production activities through the rapid development and fielding of fixed and transportable intelligence architectures capable of front-end collection and analysis
 of new technologies in near real time. Space Superiority and Space Control is only realized through Space Superiority Intelligence support on the front end of space
 acquisition, allowing increased innovation and resiliency in support of changing program/project priorities to respond and to operate in the contested space domain, as
 well as supporting lifecycle experimentation, prototyping, and risk reduction. Supports USSPACECOM Space Domain Awareness Initial Capabilities Document (ICD),
 February 2022.

 This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been
 fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.

